473→              "enum": [
474→                "beads-kanban",
475→                "static-render",
476→                "omb-board",
477→                "none"
478→              ]
479→            }
480→          }
481→        }
482→      },
483→      "allOf": [
484→        {
485→          "if": {
486→            "properties": {
487→              "mode": {
488→                "enum": [
489→                  "beads",
490→                  "both"
491→                ]
492→              }
493→            }
494→          },
495→          "then": {
496→            "required": [
497→              "beads"
498→            ]
499→          }
500→        }
