521→          "maximum": 86400
522→        },
523→        "heartbeat_seconds": {
524→          "type": "integer",
525→          "minimum": 15,
526→          "maximum": 60
527→        },
528→        "coordination_store": {
529→          "const": "git_common_dir"
530→        },
531→        "completion_write_branch": {
532→          "const": "default"
533→        },
534→        "dirty_worktree_policy": {
535→          "const": "fail_closed"
536→        }
537→      }
538→    },
539→    "claude_hooks": {
540→      "type": "object",
541→      "additionalProperties": false,
542→      "required": [
543→        "source",
544→        "project_plugin_link",
545→        "session_start",
546→        "post_tool_reconcile",
547→        "task_completed_gate"
548→      ],
549→      "properties": {
550→        "source": {
551→          "type": "string",
552→          "enum": [
553→            "plugin",
554→            "project",
555→            "disabled"
556→          ]
557→        },
558→        "project_plugin_link": {
559→          "$ref": "#/$defs/repoRelative"
560→        },
561→        "session_start": {
562→          "type": "boolean"
563→        },
564→        "post_tool_reconcile": {
565→          "type": "boolean"
566→        },
567→        "task_completed_gate": {
568→          "type": "boolean"
569→        }
570→      }
571→    },
572→    "path_policy": {
573→      "type": "object",
574→      "additionalProperties": false,
575→      "required": [
576→        "authority",
577→        "stored_paths",
578→        "allow_outside_repository",
579→        "follow_content_symlinks_outside_repository"
580→      ],
581→      "properties": {
582→        "authority": {
583→          "const": "caller-repository"
584→        },
585→        "stored_paths": {
586→          "const": "repository-relative"
587→        },
588→        "allow_outside_repository": {
589→          "const": false
590→        },
591→        "follow_content_symlinks_outside_repository": {
592→          "const": false
593→        }
594→      }
595→    }
