{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "repo-config.schema.json",
  "title": "dev-graph repository-local configuration",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "repository_id",
    "content_roots",
    "local_state",
    "github",
    "execution_tracker",
    "worktrees",
    "claude_hooks",
    "path_policy"
  ],
  "properties": {
    "schema_version": {
      "const": "1.0.0"
    },
    "repository_id": {
      "type": "string",
      "description": "C24がcanonical GitHub remoteから再導出する github:<owner>/<repo>、またはremoteなしでgit common-dir realpathから導出するlocal fingerprint。設定値と再導出値の一致を必須とする。",
      "pattern": "^(github:[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+|local:sha256:[0-9a-f]{64})$"
    },
    "content_roots": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "issues",
        "tasks",
        "specifications",
        "architecture",
        "features",
        "documents",
        "system_spec"
      ],
      "properties": {
        "issues": {
          "$ref": "#/$defs/repoRelative"
        },
        "tasks": {
          "$ref": "#/$defs/repoRelative"
        },
        "specifications": {
          "$ref": "#/$defs/repoRelative"
        },
        "architecture": {
          "$ref": "#/$defs/repoRelative"
        },
        "features": {
          "$ref": "#/$defs/repoRelative"
        },
        "documents": {
          "$ref": "#/$defs/repoRelative"
        },
        "system_spec": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "plan_roots": {
      "type": "object",
      "additionalProperties": false,
      "description": "system-dev-planner が plan の staging/published/state 置き場として読む任意セクション (promote-system-plan.py)。dev-graph 単体では未使用だが、同一 config を共有する以上 schema 側で正式に許可する (additionalProperties:false のため未定義だと実運用 config が schema 不適合になる)",
      "required": [
        "staging",
        "published",
        "state"
      ],
      "properties": {
        "staging": {
          "$ref": "#/$defs/repoRelative"
        },
        "published": {
          "$ref": "#/$defs/repoRelative"
        },
        "state": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "local_state": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "graph",
        "cache",
        "locks"
      ],
      "properties": {
        "graph": {
          "$ref": "#/$defs/repoRelative"
        },
        "cache": {
          "$ref": "#/$defs/repoRelative"
        },
        "locks": {
          "$ref": "#/$defs/repoRelative"
        }
      }
    },
    "github": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "enabled",
        "issue_repository",
        "projects",
        "completion_policy"
      ],
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "issue_repository": {
          "type": "string",
          "pattern": "^[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+$"
        },
        "projects": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": [
              "alias",
              "owner_type",
              "owner_login",
              "project_number",
              "default",
              "auto_add",
              "field_mappings"
            ],
            "properties": {
              "alias": {
                "type": "string",
                "pattern": "^[a-z0-9][a-z0-9_-]*$"
              },
              "owner_type": {
                "type": "string",
                "enum": [
                  "organization",
                  "user"
                ]
              },
              "owner_login": {
                "type": "string",
                "minLength": 1
              },
              "project_number": {
                "type": "integer",
                "minimum": 1
              },
              "default": {
                "type": "boolean"
              },
              "auto_add": {
                "type": "object",
                "additionalProperties": false,
                "required": [
                  "artifact_kinds",
                  "confirmation_status",
                  "evaluation_status",
                  "implementation_readiness"
                ],
                "properties": {
                  "artifact_kinds": {
                    "type": "array",
                    "minItems": 1,
                    "uniqueItems": true,
                    "items": {
                      "type": "string",
                      "enum": [
                        "task",
                        "issue"
                      ]
                    }
                  },
                  "confirmation_status": {
                    "const": "confirmed"
                  },
                  "evaluation_status": {
                    "const": "pass"
                  },
                  "implementation_readiness": {
                    "const": "complete"
                  }
                }
              },
              "field_mappings": {
                "type": "array",
                "items": {
                  "type": "object",
                  "additionalProperties": false,
                  "required": [
                    "local_field",
                    "project_field_name",
                    "value_type",
                    "direction",
                    "option_map"
                  ],
                  "properties": {
                    "local_field": {
                      "type": "string",
                      "enum": [
                        "status",
                        "priority",
                        "start_date",
                        "target_date",
                        "iteration"
                      ]
                    },
                    "project_field_name": {
                      "type": "string",
                      "minLength": 1
                    },
                    "value_type": {
                      "type": "string",
                      "enum": [
                        "single_select",
                        "text",
                        "number",
                        "date",
                        "iteration"
                      ]
                    },
                    "direction": {
                      "type": "string",
                      "enum": [
                        "local_to_project",
                        "bidirectional"
                      ]
                    },
                    "option_map": {
                      "type": "object",
                      "additionalProperties": {
                        "type": "string"
                      }
                    }
                  },
                  "allOf": [
                    {
                      "if": {
                        "properties": {
                          "local_field": {
                            "const": "status"
                          }
                        }
                      },
                      "then": {
                        "properties": {
                          "direction": {
                            "const": "local_to_project"
                          }
                        }
                      }
                    }
                  ]
                }
              }
            }
          }
        },
        "completion_policy": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "trigger",
            "required_pull_requests",
            "target_branch",
            "closed_unmerged",
            "issue_reopened",
            "revert",
            "local_reconciliation",
            "scheduled_reconciliation"
          ],
          "properties": {
            "trigger": {
              "const": "linked_pr_merged"
            },
            "required_pull_requests": {
              "type": "string",
              "enum": [
                "all",
                "any"
              ]
            },
            "target_branch": {
              "const": "default"
            },
            "closed_unmerged": {
              "type": "string",
              "enum": [
                "keep_active",
                "mark_blocked"
              ]
            },
            "issue_reopened": {
              "const": "reopen_task"
            },
            "revert": {
              "const": "create_follow_up_unless_issue_reopened"
            },
            "local_reconciliation": {
              "type": "array",
              "minItems": 1,
              "uniqueItems": true,
              "items": {
                "type": "string",
                "enum": [
                  "manual_sync",
                  "claude_hook",
                  "scheduled_sync"
                ]
              }
            },
            "scheduled_reconciliation": {
              "type": "object",
              "additionalProperties": false,
              "required": [
                "enabled",
                "interval_minutes",
                "owner",
                "entry_point"
              ],
              "properties": {
                "enabled": {
                  "type": "boolean"
                },
                "interval_minutes": {
                  "type": "integer",
                  "minimum": 5,
                  "maximum": 10080
                },
                "owner": {
                  "type": "string",
                  "enum": [
                    "claude_session_start",
                    "host_scheduler"
                  ]
                },
                "entry_point": {
                  "const": "dev-graph sync --reconcile-lifecycle"
                }
              }
            }
          },
          "allOf": [
            {
              "if": {
                "properties": {
                  "local_reconciliation": {
                    "contains": {
                      "const": "scheduled_sync"
                    }
                  }
                }
              },
              "then": {
                "properties": {
                  "scheduled_reconciliation": {
                    "properties": {
                      "enabled": {
                        "const": true
                      }
                    }
                  }
                }
              }
            },
            {
              "if": {
                "properties": {
                  "scheduled_reconciliation": {
                    "properties": {
                      "enabled": {
                        "const": true
                      }
                    }
                  }
                }
              },
              "then": {
                "properties": {
                  "local_reconciliation": {
                    "contains": {
                      "const": "scheduled_sync"
                    }
                  }
                }
              }
            }
          ]
        }
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "enabled": {
                "const": true
              }
            }
          },
          "then": {
            "properties": {
              "projects": {
                "minItems": 1,
                "contains": {
                  "type": "object",
                  "properties": {
                    "default": {
                      "const": true
                    }
                  },
                  "required": [
                    "default"
                  ]
                },
                "minContains": 1,
                "maxContains": 1
              }
            }
          }
        }
      ]
    },
    "execution_tracker": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "mode"
      ],
      "description": "repo単位の実行トラッカー選択。既定・repoプロファイル別の選択基準はreferences/execution-tracker-contract.md §1の決定表を正本とする。",
      "properties": {
        "mode": {
          "type": "string",
          "enum": [
            "beads",
            "github",
            "both"
          ]
        },
        "beads": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "issue_prefix",
            "server_mode",
            "github_mirror",
            "board"
          ],
          "properties": {
            "issue_prefix": {
              "type": "string",
              "pattern": "^[a-z][a-z0-9-]*$"
            },
            "server_mode": {
              "type": "boolean",
              "description": "bd を server モードで運用するか。strandkanban 0.5.x (旧称 beads-kanban) は bd export/update 等の CLI で読み書きし bd sql を使わないため、board=beads-kanban でも embedded (false) のままでよい (旧版の bd sql 読取時代にあった true 強制は撤廃。契約 §9.1 正本)。"
            },
            "github_mirror": {
              "type": "string",
              "enum": [
                "bd_github_push_only",
                "none"
              ]
            },
            "board": {
              "type": "string",
              "description": "beads 束縛タスクの live 看板 UI 選択 (references/execution-tracker-contract.md §9 正本)。beads-kanban=doublej/strandkanban (旧称 beads-kanban、enum 値は後方互換のため旧名を維持。embedded bd で動作・clone+install で起動・外部依存・LICENSE要確認)。static-render=C05 render-graph-html のゼロ依存スナップショットのみ。omb-board=oh-my-beads 同梱の軽量 board (embedded 可)。none=看板なし。",
              "enum": [
                "beads-kanban",
                "static-render",
                "omb-board",
                "none"
              ]
            }
          }
        }
      },
      "allOf": [
        {
          "if": {
            "properties": {
              "mode": {
                "enum": [
                  "beads",
                  "both"
                ]
              }
            }
          },
          "then": {
            "required": [
              "beads"
            ]
          }
        }
      ]
    },
    "worktrees": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "enabled",
        "lease_ttl_seconds",
        "heartbeat_seconds",
        "coordination_store",
        "completion_write_branch",
        "dirty_worktree_policy"
      ],
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "lease_ttl_seconds": {
          "type": "integer",
          "minimum": 300,
          "maximum": 86400
        },
        "heartbeat_seconds": {
          "type": "integer",
          "minimum": 15,
          "maximum": 60
        },
        "coordination_store": {
          "const": "git_common_dir"
        },
        "completion_write_branch": {
          "const": "default"
        },
        "dirty_worktree_policy": {
          "const": "fail_closed"
        }
      }
    },
    "claude_hooks": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "source",
        "project_plugin_link",
        "session_start",
        "post_tool_reconcile",
        "task_completed_gate"
      ],
      "properties": {
        "source": {
          "type": "string",
          "enum": [
            "plugin",
            "project",
            "disabled"
          ]
        },
        "project_plugin_link": {
          "$ref": "#/$defs/repoRelative"
        },
        "session_start": {
          "type": "boolean"
        },
        "post_tool_reconcile": {
          "type": "boolean"
        },
        "task_completed_gate": {
          "type": "boolean"
        }
      }
    },
    "path_policy": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "authority",
        "stored_paths",
        "allow_outside_repository",
        "follow_content_symlinks_outside_repository"
      ],
      "properties": {
        "authority": {
          "const": "caller-repository"
        },
        "stored_paths": {
          "const": "repository-relative"
        },
        "allow_outside_repository": {
          "const": false
        },
        "follow_content_symlinks_outside_repository": {
          "const": false
        }
      }
    }
  },
  "allOf": [
    {
      "if": {
        "properties": {
          "execution_tracker": {
            "properties": {
              "mode": {
                "enum": [
                  "github",
                  "both"
                ]
              }
            }
          }
        }
      },
      "then": {
        "properties": {
          "github": {
            "properties": {
              "enabled": {
                "const": true
              }
            }
          }
        }
      }
    }
  ],
  "$defs": {
    "repoRelative": {
      "type": "string",
      "minLength": 1,
      "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "graph-node.schema.json",
  "title": "dev-graph タスクグラフノード (draft)",
  "description": "run-plugin-dev-plan が manual-apply artifact として出力する schema draft。後段 builder または人手承認で plugins/dev-graph/schemas/graph-node.schema.json へ適用する。issue/task/specification/architecture/feature/document の各成果物を単一グラフ構造で表現し、issues/tasks/specs/architecture/features/docs の正規ディレクトリへ自動routingする。feature はマクロ層 (purpose/goal/scope/acceptance/architecture_refs) を保持し、細タスク仕様書生成は external plugin system-dev-planner (ミクロ層) へ委譲する (MM-01)。",
  "type": "object",
  "required": [
    "graph_node_id",
    "artifact_kind",
    "artifact_subtypes",
    "title",
    "project_id",
    "domain",
    "status",
    "owners",
    "tags",
    "priority",
    "start_date",
    "target_date",
    "iteration",
    "created_at",
    "updated_at",
    "depends_on",
    "related_nodes",
    "resource_scope",
    "parent_feature",
    "feature_package_id",
    "phase_ref",
    "file_path",
    "template_id",
    "template_version",
    "confirmation_status",
    "evaluation_status",
    "confirmation_evidence",
    "source_lineage",
    "classification_confidence",
    "classification_reason",
    "classification_candidates",
    "github_publication",
    "issue_linkage",
    "tracker_binding",
    "beads_linkage",
    "github_project_linkages",
    "pull_request_linkages",
    "execution_contexts",
    "completion_evidence",
    "implementation_readiness"
  ],
  "properties": {
    "graph_node_id": {
      "type": "string",
      "minLength": 1,
      "description": "移動・再分類・GitHub同期後も変化しない論理identity。file_pathはこのIDを参照する可変projectionでありidentityに使わない"
    },
    "id": {
      "type": "string",
      "deprecated": true,
      "description": "後方互換alias。新規成果物ではgraph_node_idを正本とする"
    },
    "artifact_kind": {
      "type": "string",
      "enum": [
        "issue",
        "task",
        "specification",
        "architecture",
        "feature",
        "document"
      ],
      "description": "成果物種別。正規rootへ issue→issues/task→tasks/specification→specs/architecture→architecture/feature→features/document→docs と決定論写像する。feature はマクロ層の機能単位ノード (purpose/goal/scope_in/scope_out/acceptance/architecture_refs を第一級に保持、MM-01)"
    },
    "artifact_subtypes": {
      "type": "array",
      "items": {
        "type": "string",
        "enum": [
          "frontend",
          "backend",
          "infrastructure",
          "data",
          "security",
          "api"
        ]
      },
      "uniqueItems": true,
      "description": "architecture subtype または specification の conditional template。architecture は1種以上、非該当kindは空配列を許す"
    },
    "kind": {
      "type": "string",
      "deprecated": true,
      "enum": [
        "issue",
        "task",
        "specification",
        "architecture",
        "feature",
        "document"
      ],
      "description": "後方互換alias。新規成果物ではartifact_kindを正本とする"
    },
    "project_id": {
      "type": "string",
      "minLength": 1,
      "description": "横断分類用project identifier。物理top-levelを決めず、閾値超過時だけsecondary partitionに使う"
    },
    "domain": {
      "type": "string",
      "minLength": 1,
      "description": "横断分類用domain。1 leafが200件を超えた場合の第一partition key"
    },
    "tags": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "uniqueItems": true,
      "description": "物理配置から独立した横断検索タグ"
    },
    "priority": {
      "type": [
        "string",
        "null"
      ],
      "description": "tracker/Projectsへ投影可能なrepo-local priority。nullは未設定"
    },
    "start_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "target_date": {
      "type": [
        "string",
        "null"
      ],
      "format": "date"
    },
    "iteration": {
      "type": [
        "string",
        "null"
      ],
      "description": "Projects iteration title等へ写像する安定した人間可読値"
    },
    "title": {
      "type": "string",
      "minLength": 1
    },
    "owners": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "成果物の更新責任者"
    },
    "created_at": {
      "type": "string",
      "format": "date-time"
    },
    "updated_at": {
      "type": "string",
      "format": "date-time",
      "description": "id + updated_at がGitHub双方向同期(要件C4)の競合解決キー"
    },
    "status": {
      "type": "string",
      "enum": [
        "draft",
        "active",
        "blocked",
        "done",
        "closed",
        "tombstoned"
      ],
      "description": "全artifact共通workflow state。GitHub Issue openはactive、closeはclosedへ写像し、delete相当はtombstonedで物理削除しない"
    },
    "closed_at": {
      "type": [
        "string",
        "null"
      ],
      "format": "date-time",
      "description": "status=closed|tombstoned に遷移した時刻。close/delete のtombstone双方向伝播(要件C12)がこの時刻を記録する"
    },
    "depends_on": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "依存先ノードid配列。ready-set算出(要件C8)の入力。feature ノード間の機能間依存もこのフィールドを流用する (新フィールド不要・MM-01)"
    },
    "related_nodes": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "uniqueItems": true,
      "description": "順序依存を持たない関連ノード参照"
    },
    "resource_scope": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
      },
      "description": "touches: このノードが触るファイル/ディレクトリパス配列。既定はディレクトリ単位、ノードがファイル単位を明示した場合はファイル単位を優先し、双方混在時は広い方(ディレクトリ単位)へフォールバックする。並列バッチのresource_scope重複回避(要件C10)の土台"
    },
    "purpose": {
      "type": [
        "string",
        "null"
      ],
      "description": "feature ノードがなぜ必要かの説明 (JTBD/価値)。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)"
    },
    "goal": {
      "type": [
        "string",
        "null"
      ],
      "description": "feature ノードが達成する到達状態。旧 目標+ゴールの語彙を1本に統合した表現。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)。program全体のgoalはgoal-spec.jsonが正本で、本フィールドは機能単位に閉じる"
    },
    "scope_in": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードのスコープ内。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "scope_out": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードのスコープ外。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "acceptance": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "description": "feature ノードが確実に実行したい観測可能な二値条件。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
    },
    "architecture_refs": {
      "type": "array",
      "items": {
        "type": "string",
        "minLength": 1
      },
      "uniqueItems": true,
      "description": "feature ノードが参照する architecture ノードの graph_node_id 配列。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)。system-spec-harness由来のarchitectureはlineage参照のみで複製しない (MM-12)"
    },
    "parent_feature": {
      "type": [
        "string",
        "null"
      ],
      "description": "task ノードが属する feature ノードの graph_node_id。artifact_kind=task かつ feature 由来のときのみ非null (feature文脈を持たない単発taskはnull可)。artifact_kind!=task では常にnull。順序依存のないrelated_nodesや複数依存を表すdepends_onとは別概念の単一親参照 (MM-03)"
    },
    "feature_package_id": {
      "type": ["string", "null"],
      "pattern": "^feature-package/[A-Za-z0-9._/-]+$",
      "description": "system-dev-plannerが1 featureから生成したexact 13 task package identity。feature由来taskは非null、他artifactと単発taskはnull"
    },
    "phase_ref": {
      "type": ["string", "null"],
      "enum": [null, "P01", "P02", "P03", "P04", "P05", "P06", "P07", "P08", "P09", "P10", "P11", "P12", "P13"],
      "description": "feature execution package内の一意phase slot。P01..P13各1件。feature由来task以外はnull"
    },
    "file_path": {
      "type": "string",
      "pattern": "^(issues|tasks|specs|architecture|features|docs)/.+\\.md$",
      "description": "全artifactが持つ正規root配下の人間可読Markdownへの参照。graph_node_idは不変、file_pathはrouting policyとpartition状態から再計算可能な派生値。feature は features/ 配下 (MM-02)"
    },
    "template_id": {
      "type": "string",
      "enum": [
        "issue",
        "task",
        "document",
        "specification",
        "architecture",
        "feature"
      ],
      "description": "artifact_kindから自動選択した基底テンプレート"
    },
    "template_version": {
      "type": "string",
      "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$",
      "description": "生成時に使用したテンプレート契約版。正本更新時は既存文書を全書換せずmigration previewへ使う"
    },
    "confirmation_status": {
      "type": "string",
      "enum": [
        "draft",
        "confirmed",
        "superseded"
      ],
      "description": "内容確定状態。system plan入力はspecification/architectureがconfirmedであることを要求する"
    },
    "evaluation_status": {
      "type": "string",
      "enum": [
        "pending",
        "pass",
        "fail",
        "stale"
      ],
      "description": "独立評価状態。C14/C15/C04はpass以外をIssue起票・推薦・実装handoff対象にしない"
    },
    "confirmation_evidence": {
      "type": "object",
      "required": [
        "evaluator",
        "evidence_ref",
        "evaluated_digest"
      ],
      "properties": {
        "evaluator": {
          "type": [
            "string",
            "null"
          ]
        },
        "evidence_ref": {
          "type": [
            "string",
            "null"
          ]
        },
        "evaluated_digest": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^[a-f0-9]{64}$"
        }
      },
      "additionalProperties": false,
      "description": "confirmation/evaluationを同一artifact digestへpinしstale PASSを拒否する"
    },
    "source_lineage": {
      "type": "object",
      "required": [
        "origin_kind",
        "source_plugin",
        "source_path",
        "source_version",
        "source_digest",
        "imported_at"
      ],
      "properties": {
        "origin_kind": {
          "type": "string",
          "enum": [
            "manual",
            "github",
            "system-spec-harness",
            "system-dev-planner",
            "generated"
          ]
        },
        "source_plugin": {
          "type": [
            "string",
            "null"
          ]
        },
        "source_path": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
        },
        "source_version": {
          "type": [
            "string",
            "null"
          ]
        },
        "source_digest": {
          "type": [
            "string",
            "null"
          ],
          "pattern": "^[a-f0-9]{64}$"
        },
        "imported_at": {
          "type": [
